        // view; the cadence is bounded by pollMs, and a terminal status / unmount
        // still stops it.
        timerRef.current = setTimeout(tick, pollMs);
      }
    };
    void tick();
    return () => {
      active = false;
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [runId, pollMs]);

