    return (
      <Flex gap={6} align="center">
        <Spin size="small" />
        <Typography.Text type="secondary">pending</Typography.Text>
      </Flex>
    );
  }
  return <Tag color={RESULT_STATUS_COLORS[status]}>{status}</Tag>;
}

